import '../models/sync_conflict.dart';class SyncConflictDetector{List<SyncConflict> compare({required Map<String,String> localHashes,required Map<String,String> remoteHashes}){final paths={...localHashes.keys,...remoteHashes.keys};final out=<SyncConflict>[];for(final path in paths){final l=localHashes[path];final r=remoteHashes[path];if(l==null){out.add(SyncConflict(path:path,type:SyncConflictType.remoteOnly,localHash:null,remoteHash:r));}else if(r==null){out.add(SyncConflict(path:path,type:SyncConflictType.localOnly,localHash:l,remoteHash:null));}else if(l==r){out.add(SyncConflict(path:path,type:SyncConflictType.identical,localHash:l,remoteHash:r));}else{out.add(SyncConflict(path:path,type:SyncConflictType.bothChanged,localHash:l,remoteHash:r));}}out.sort((a,b)=>a.path.compareTo(b.path));return out;}}
